VALUES
  ('heelevel3-d0d1b9a2-moex-00005', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年期初存貨為$5,000，期末存貨為$3,000，X1年間進貨$50,000，進貨退回$3,000， 進貨折讓$1,000，進貨運費$2,000，尚有$1,000之應付但未付款之進貨尚未記入帳簿。若銷貨 收入$80,000，銷貨退回$5,000，銷貨折讓$2,000，銷貨運費$1,000（由賣方負擔，列為營業費 用），則甲公司X1年度之銷貨成本為何？', '["$48,000", "$49,000", "$51,000", "$53,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00006', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司的機器於X4年12月31日的帳列成本為$8,000，累計折舊為$1,600。該日該機器的公 允價值為$5,000。若甲公司採用「消除成本法（即沖銷累計折舊）」的方式處理重估，則下列 選項何者正確？', '["直接將機器的帳面金額減至$5,000，並將損失列入其他綜合損益", "沖銷累計折舊$1,600，並認列重估價損失$1,400", "認列重估價損失$3,000，並調整機器的帳面金額至$5,000", "維持原帳面金額不調整，待除列機器時，再重分類至損益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00007', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年4月1日以$64,000買進乙公司25%的普通股股權，並對乙公司財務業務決策 具有重大影響。當日乙公司的淨資產為$320,000，且甲公司的投資成本與所享有股權淨值份 額間無差額。乙公司X1年度之淨利為$100,000，且於X1年間平均產生。若X1年度應發放 之累積特別股現金股利為$20,000，但乙公司並未宣告發放，且特別股股本金額沒有改變，則 X1年4月1日特別股股本為何？', '["$80,000", "$64,000", "$32,000", "$20,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00008', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X0年12月31日向乙銀行借款$2,000,000，開立三年期票據，票面利率6%，每年 年底付息一次，到期日為X3年12月31日。借款當日有效利率亦為6%。截至X2年底已正 常支付兩年利息，但X2年12月31日甲公司發生財務困難，經乙銀行同意本金減為$1,800,000， 利率降為3%，每年年底支付利息，到期日延長至X5年12月31日，但甲公司當日需支付乙 銀行債務協商費用$10,000。若當日市場有效利率為7%，則甲公司在X2年12月31日債務 清償損益為何？ （P =2.673012；p =0.839619；P =2.624316；p =0.816298） 3,6% 3,6% 3,7% 3,7%', '["$358,591", "$368,591", "$378,951", "$388,591"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00009', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日，以平價發行面額總計$2,000,000的4年期可轉換公司債，票面利率', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00010', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '0%，每年付息一次；該債券可於到期日前任何時點，按每$1,000面額轉換為100股面額$10 之普通股。若發行日不附轉換權但條件相同的公司債市場利率為8.0%，且該可轉換債券於發 行日之負債組成部分公允價值約為$1,735,000。若甲公司於X2年1月1日以現金$2,050,000 買回全部流通在外的可轉換公司債，且買回時，負債組成部分的帳面金額已攤銷至$1,793,800， 當時公允價值為$1,700,000，則X2年1月1日這筆可轉換公司債買回交易，對甲公司權益總 額的淨影響為何？', '["減少$178,800", "減少$256,200", "減少$350,000", "減少$443,800"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00011', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年底有下列會計項目的貸方餘額。若每項的餘額均為$1,000，則X1年底資產負 債表下的其他權益貸方餘額為何？ ㉑透過其他綜合損益按公允價值衡量之債務工具投資未實現損益 ㉒透過其他綜合損益按公允價值衡量之權益工具投資未實現損益 ㉓投資性不動產公允價值調整利益 ㉔不動產重估增值 ㉕確定福利計畫之再衡量數 ㉖停業單位利益', '["$2,000", "$3,000", "$4,000", "$5,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00012', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初與諸多客戶分別簽訂合約，以$10,000提供一年健身會員服務。合約包含一 項選擇權：客戶可於未來兩年內每年續約一次，每次僅需支付$8,000，即可再享一年服務。若 客戶未於X1年初簽約，則X2年與X3年的正常價格分別為$12,000及$14,000。甲公司評估 此續約選項具有重大優惠，構成一項重要權利，應視為一個單獨履約義務。甲公司於 X1 年 初預期X1年簽約客戶中有70%的客戶將於X2年續約，而X1年簽約客戶中有50%將於X3 年續約，且每名客戶每年的預期總成本為：X1年：$5,080、X2年：$6,000、X3年：$7,000。 若甲公司判定以已發生成本相對於預期總成本為基礎認列收入，且 X1 年之實際成本亦為 $5,080，則甲公司於X1年應認列服務收入之金額為何（百分比請四捨五入為整數）？', '["$520", "$6,820", "$7,840", "$19,600"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00013', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於20X1年1月1日發行不可轉換，不可賣回，每股面值$10的累積特別股2,000股， 自20X3年起，特別股股東獲得股利率5%，此等股利率等同於其他相同等級特別股於20X1 年1月1日發行的市場股利率。試問：甲公司計算20X2年度的基本每股盈餘，視為特別股 股利之金額為何？', '["$0", "$907.03", "$952.38", "$1,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00014', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '丙公司於20X1年1月1日與客戶簽訂合約，共計銷售500單位產品，每單位售價$20，每單 位成本$15，在合約簽訂日移轉產品控制權予客戶，並收取現金。丙公司依據商業慣例允許客 戶於20天內退回未使用之產品，客戶可收到全額退款。丙公司的上述銷售附退貨權之產品， 自客戶收取的對價係變動，會計人員決定以期望值方法，預測將有權取得的變動對價的產品 數為450單位，亦即450單位產品高度很有可能不會發生重大迴轉於退貨期間內。試問：下 列何者為丙公司於20X1年1月1 日的正確記錄？', '["銷貨收入增加$10,000", "銷貨成本增加$6,750", "退款負債增加$750", "存貨減少$6,750"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
